-    /// Verifies that a "streaming POST" can reuse an existing established connection.
-    private static void testStreamingPostRequestCanReuseConnection(
-            boolean secure,
-            ThrowingConsumer<HttpURLConnection> preConnectConsumer,
-            ThrowingBiConsumer<BufferedReader, List<String>> requestVerifier)
-            throws Throwable {
-        try (var serverSocket = createServerSocket(secure)) {
-
-            // Issue the initial HEAD request to admit a connection to the cache
-            var responseCodeFuture = executeRequest(
-                    secure,
-                    serverSocket,
-                    connection -> connection.setRequestMethod("HEAD"),
-                    _ -> {});
-
-            // Accept the initial HEAD request
-            try (var clientSocket = serverSocket.accept();
-                 var clientOutputWriter = new BufferedWriter(
