-                 var clientInputReader = new BufferedReader(
-                         new InputStreamReader(clientSocket.getInputStream(), CHARSET))) {
-
-                verifyInitialHeadRequest(
-                        clientInputReader, clientOutputWriter, responseCodeFuture);
-
-                // -------------------------------------------------------------
-                // At this stage the connection is assumed to be admitted into
-                // the keep-alive cache. Consequently, it should be reused for
-                // the following "streaming POST".
-                // -------------------------------------------------------------
-
-                // Issue a "streaming POST" request
-                responseCodeFuture = executeRequest(
-                        secure,
-                        serverSocket,
-                        preConnectConsumer,
-                        connection -> {
-                            try (var requestOutputStream = connection.getOutputStream()) {
