-    private static void verifySocketClosed(BufferedReader clientInputReader) throws Exception {
-        LOGGER.info("Verifying that the socket is closed...");
-        var readLineFuture = new CompletableFuture<String>();
-        var stopFlag = new AtomicBoolean(false);
-        var thread = Thread.ofVirtual()
-                .uncaughtExceptionHandler((_, e) -> readLineFuture.completeExceptionally(e))
-                .start(() -> {
-                    while (!stopFlag.get()) {
-                        try {
-                            var readLine = clientInputReader.readLine();
-                            readLineFuture.complete(readLine);
-                        } catch (IOException _) {
-                            readLineFuture.complete(null);
-                        }
-                        LockSupport.parkNanos(Duration.ofMillis(100).toNanos());
-                    }
-                });
-        try {
-            var readLine = readLineFuture.get(adjustTimeout(5), TimeUnit.SECONDS);
-            assertNull(readLine, "Unexpected line read!");
-        } finally {
-            stopFlag.set(true);
-            thread.interrupt();
-        }
-    }
